INSERT INTO public.course_details (course_id, entry_requirements, admission_test_info, interview_info, documents_required, personal_statement_guidelines, additional_info) VALUES ('8b3d1429-e6c9-4fd4-be61-69d91384fcff', 'Good results in Level 4 Mathematics and Science. Applicants with a Foundation Certificate or Access to HE Diploma are considered. Interview required.', 'No formal admission test required.', 'Interview may be required as part of the application process.', 'Academic transcripts, proof of English language proficiency, valid ID/passport.', 'Not specifically required for this programme.', 'Delivered in partnership with the University of Bolton. Accredited by the Institution of Engineering and Technology (IET).'), ('24f912bf-1158-44b9-8f6e-8fe353ef2b5a', 'Minimum of two GCE A2-level passes (or equivalent) in any subjects. Five GCSEs at grade C or above (or equivalent), including English Language and Mathematics. If English is not your first language, IELTS 5.0 with no band lower than 4.5 (or equivalent). Applicants with non-traditional entry qualifications or relevant experience will be considered.', 'No formal admission test required.', 'You may be required to attend an interview and/or provide a portfolio of work.', 'Academic transcripts, GCSE/A-Level certificates, proof of English language proficiency (IELTS or equivalent), valid ID/passport.', 'Not specifically required for this programme.', 'This is a 4-year programme with Foundation Year. Delivered in partnership with the University of Bolton.'), ('5904b984-2b83-4052-ae6b-afd4f926474c', 'Minimum of two GCE A2-level passes (or equivalent) in any subjects. Five GCSEs at grade C or above (or equivalent), including English and Mathematics. If English is not your first language, IELTS 6.0 or equivalent. Applicants without GCSEs can contact the institution for details of other acceptable qualifications.', 'No formal admission test required.', 'You may be required to attend an interview and/or provide a portfolio of work.', 'Academic transcripts, GCSE/A-Level certificates, proof of English language proficiency (IELTS or equivalent), valid ID/passport.', 'Not specifically required for this programme.', 'This programme includes a Foundation Year. Delivered in partnership with the University of Bolton.'), ('33a325b9-59fa-46f6-90d5-39097e5f1434', 'Minimum of two GCE A2-level passes (or equivalent) in any subjects. Five GCSEs at grade C or above (or equivalent) in any subjects. If English is not your first language, IELTS 6.0 or equivalent. Top-up entry requires completion of a relevant Level 5 qualification (e.g., HND or Foundation Degree in Health and Social Care).', 'No formal admission test required.', 'You may be required to attend an interview and/or provide a portfolio of work. DBS Enhanced Disclosure may be required for placements involving regulated activity.', 'Academic transcripts, Level 5 qualification certificate, proof of English language proficiency, valid ID/passport, DBS Enhanced Disclosure (for placements).', 'Not specifically required for this programme.', 'DBS check required for work placements involving unsupervised access to children/vulnerable adults. Delivered in partnership with the University of Bolton.'), ('c2b928a6-8ba3-4121-bbf8-b5c2517ee55a', 'A BTEC Level 3 qualification in Computing, Business or Creative Digital Media Production, or other related Level 3 qualifications. A GCE Advanced Level profile with strong performance in a relevant subject, supported by GCSE grades A* to C (9 to 4) in Mathematics and English. An Access to Higher Education Diploma. Relevant work experience or international equivalent. RPL considered. Non-native English: CEFR B2, PTE Academic 51, or IELTS 5.5 with Reading and Writing at 5.5.', 'No formal admission test required.', 'Interview may be required as part of the application process.', 'Academic transcripts, Level 3 qualification certificates, proof of English language proficiency, valid ID/passport.', 'Not specifically required for this programme.', 'Pearson BTEC Level 4 qualification. Registration fee of £278.00 applies. Delivered in partnership with Pearson.'), ('9d2899ed-b308-442e-ae6f-a1e2132757f8', 'A BTEC Level 3 qualification in Engineering or related Level 3 qualifications. A GCE Advanced Level profile with strong performance in a relevant subject, supported by GCSE grades A* to C (9 to 4) in Mathematics and English. An Access to Higher Education Diploma. Relevant work experience or international equivalent. RPL considered. Non-native English: CEFR B2, PTE Academic 51, or IELTS 5.5 with Reading and Writing at 5.5.', 'No formal admission test required.', 'Interview may be required as part of the application process.', 'Academic transcripts, Level 3 qualification certificates, proof of English language proficiency, valid ID/passport.', 'Not specifically required for this programme.', 'Pearson BTEC Level 4 qualification. Registration fee of £278.00 applies. Delivered in partnership with Pearson.'), ('39b1c344-93bf-4419-a3eb-f21bd8d34b82', 'GCSE passes at grades A to C including English Language, and either minimum one A Level at grades A to E, or BTEC Level 3 Certificate/Diploma, or Access to HE Certificate. College-recognised equivalent qualifications accepted (NARIC database used). Alternatively, two or more years of work experience at managerial/supervisory/admin level with personal statement, work experience form, interview and employment references.', 'No formal admission test required.', 'Interview may be required, especially for applicants entering via work experience route.', 'Academic transcripts, GCSE/A-Level certificates or equivalent, employment references (if work experience route), proof of English language proficiency, valid ID/passport.', 'Personal statement required for applicants entering via work experience route.', 'Pearson BTEC Level 4 qualification. Registration fee of £278.00 applies. Delivered in partnership with Pearson.'), ('094bfaab-d709-495e-aa08-5fe5f443989f', 'A BTEC Level 3 qualification in Health and Social Care or related subject. A GCE Advanced Level profile with strong performance in a relevant subject, supported by GCSE grades A* to C (9 to 4) in Mathematics and English. An Access to Higher Education Diploma. Relevant work experience or international equivalent. RPL considered. Non-native English: CEFR B2, PTE Academic 51, or IELTS 5.5 with Reading and Writing at 5.5.', 'No formal admission test required.', 'Interview may be required. DBS Enhanced Disclosure may be needed for placements.', 'Academic transcripts, Level 3 qualification certificates, proof of English language proficiency, valid ID/passport, DBS Enhanced Disclosure (if required).', 'Not specifically required for this programme.', 'Pearson BTEC Level 4 qualification. Registration fee of £278.00 applies. Delivered in partnership with Pearson. DBS check may be required for work placements.'), ('f1328294-0520-489a-9c14-98b66f61bc72', 'Successfully completed honours degree (or equivalent) in a relevant subject with appropriate work experience. Normally 2.1 or above Honours degree in Psychology accredited by BPS for GBR. 2.2 in Psychology may be accepted following interview with Programme Leader. Alternative related degrees (nursing, health and social care) may be accepted following interview. If English is not first language, IELTS 6.0 with no band less than 5.5.', 'No formal admission test required.', 'Interview may be required, particularly for applicants with a 2.2 degree or alternative related degrees.', 'Honours degree certificate and transcripts, proof of English language proficiency, valid ID/passport, portfolio of work (if requested).', 'Not specifically required for this programme.', 'Delivered in partnership with the University of Bolton. This course does NOT confer Graduate Basis for Registration with the BPS.'), ('5b077bdf-ef6e-45d6-8d4c-598019977dfa', 'Completion of a relevant Level 5 qualification (e.g., HND, Foundation Degree, or DipHE in Business Management or related field). Minimum of 240 credits at Level 4 and Level 5. GCSE English and Mathematics at grade C/4 or above (or equivalent). Non-native English speakers: IELTS 6.0 or equivalent.', 'No formal admission test required.', 'Online or in-person interview required. Applicants contacted within 7 working days of submission.', 'Level 5 qualification certificate and transcripts, GCSE certificates, proof of English language proficiency, valid ID/passport.', 'Not specifically required for this programme.', 'Top-up programme (1 year). Student Finance England available for eligible UK students.'), ('d143a0fe-f6e2-411c-a6a4-5fb4201049d0', 'A relevant Level 3 qualification or equivalent (e.g., BTEC Level 3 Diploma, A-Levels, Access to HE Diploma). GCSE English and Mathematics at grade C/4 or above (or equivalent). Relevant work experience may be considered. Non-native English speakers: IELTS 5.5 or equivalent.', 'No formal admission test required.', 'Online or in-person interview required. Applicants contacted within 7 working days of submission.', 'Academic transcripts, qualification certificates, proof of English language proficiency, valid ID/passport.', 'Not specifically required for this programme.', 'Blended learning mode. Delivered at CECOS College London. Student Finance England available for eligible UK students.'), ('4f80b4f9-71b1-4cae-b1cf-0d29a3c3a41d', 'A relevant Level 3 qualification in Health and Social Care or related field (e.g., BTEC Level 3, Access to HE Diploma, NVQ Level 3). GCSE English and Mathematics at grade C/4 or above (or equivalent). Relevant work experience in health and social care may be considered. Non-native English speakers: IELTS 5.5 or equivalent.', 'No formal admission test required.', 'Online or in-person interview required. Applicants contacted within 7 working days of submission.', 'Academic transcripts, qualification certificates, proof of English language proficiency, valid ID/passport. DBS Enhanced Disclosure may be required.', 'Not specifically required for this programme.', 'Blended learning mode. Delivered at CECOS College London. DBS check may be required for work placements. Student Finance England available for eligible UK students.') ON CONFLICT (course_id) DO UPDATE SET entry_requirements = EXCLUDED.entry_requirements, admission_test_info = EXCLUDED.admission_test_info, interview_info = EXCLUDED.interview_info, documents_required = EXCLUDED.documents_required, personal_statement_guidelines = EXCLUDED.personal_statement_guidelines, additional_info = EXCLUDED.additional_info, updated_at = now()